const htmlToText = (h) => (h || '').replace(/<!--[\s\S]*?-->/g, ' ').replace(/<(style|script)[\s\S]*?<\/\1>/gi, ' ').replace(/<[^>]+>/g, ' ').replace(/&nbsp;/gi, ' ').replace(/&amp;/gi, '&').replace(/&lt;/gi, '<').replace(/&gt;/gi, '>').replace(/&[#a-z0-9]+;/gi, ' ').replace(/\s+/g, ' ').trim();
return $input.all().map((item, i) => {
  const subject = item.json.subject || '';
  const from = item.json.from || '';
  const stripped = htmlToText(item.json.html || item.json.textHtml || item.json.textAsHtml || '');
  const text = (((item.json.text || '') + ' ' + stripped).trim() || item.json.snippet || '').slice(0, 6000);
  const system = "You classify job-application emails and output JSON only. Set is_application_confirmation=true when the email confirms the user has ALREADY SUBMITTED an application for a specific role (e.g. 'we received your application', 'thanks for applying', 'Application submitted', 'the following items were sent to <employer>'). Set is_application_confirmation=false for: reminders to COMPLETE, FINISH, CONTINUE, or SUBMIT an application ('almost there', 'complete your application', 'finish applying') which mean it was NOT submitted; interview invites; rejections; job alerts or recommendations; newsletters; marketing. Company is the actual HIRING employer, NOT the job board or ATS platform (Indeed, LinkedIn, Glassdoor, Greenhouse, Lever, Workday, Ashby); these platforms often send the confirmation on the employer's behalf, so extract the employer named in the body. For example, an Indeed email saying 'Application submitted' and 'the following items were sent to Gifthealth Inc' has company 'Gifthealth Inc', not Indeed. Only set false and leave company empty if NO real employer is named anywhere. Role is the job title; it usually follows 'your application for', 'the position of', or 'the role of', or appears near the top of the email, and may be preceded by a requisition/job ID (e.g. R0954602) and followed by a status like (Open) - extract only the readable title and drop the ID and status. Examples: from 'received your application for: R0954602 IT Operations Analyst (OhioRISE) (Open)' the role is 'IT Operations Analyst (OhioRISE)'; an Indeed email for 'IT Support Specialist I' at Gifthealth Inc has role 'IT Support Specialist I'. If it is not a confirmation or a field is truly unknown, use an empty string for that field.";
  return {
    json: {
      gmailId: item.json.id,
      ollamaBody: {
        model: 'qwen2.5:7b-instruct',
        stream: false,
        options: { temperature: 0 },
        format: {
          type: 'object',
          properties: {
            is_application_confirmation: { type: 'boolean' },
            company: { type: 'string' },
            role: { type: 'string' }
          },
          required: ['is_application_confirmation', 'company', 'role']
        },
        messages: [
          { role: 'system', content: system },
          { role: 'user', content: `Subject: ${subject}\n\nFrom: ${from}\n\nBody:\n${text}` }
        ]
      }
    },
    pairedItem: { item: i }
  };
});

const prompts = $('Build prompt').all();
return $input.all().map((item, i) => {
  const parsed = JSON.parse(item.json.message.content);
  return {
    json: { ...parsed, gmailId: prompts[i].json.gmailId },
    pairedItem: { item: i }
  };
});
